export function getTeamsByLeague(leagueId: string): Team[] {
  switch (leagueId) {
    case 'nhl':
      return NHL_TEAMS;
    case 'nba':
      return NBA_TEAMS;
    case 'nfl':
      return NFL_TEAMS;
    case 'mlb':
      return MLB_TEAMS;
    case 'mls':
      return MLS_TEAMS;
    default:
      return [];
  }
}
